cmd:
find /mnt/ace/ -type f \( -iname "*.xlsx" -o -iname "*.xls" -o -iname "*.xlsm" \) ! -name "~$*" -printf "%p|%s|%TY-%Tm-%Td %TH:%TM\n" 2>/dev/null | awk -F'|' '{
  split($1, a, "/");
  # Top-level is a[4] (since path starts with /mnt/ace/)
  topdir = a[4];
  count[topdir]++;
  size[topdir] += $2;
  files[topdir] = files[topdir] $1 "|" $2 "|" $3 "\n";
}
END {
  for (d in count) {
    printf "TOP-DIR: %s | FILES: %d | TOTAL-SIZE: %d bytes\n", d, count[d], size[d];
  }
}' | sort

# Get a sample of files for each top-level dir (first 10 per dir) for the detailed listing
find /mnt/ace/ -type f \( -iname "*.xlsx" -o -iname "*.xls" -o -iname "*.xlsm" \) ! -name "~$*" -printf "%p|%s|%TY-%Tm-%Td\n" 2>/dev/null | awk -F'|' '{
  split($1, a, "/");
  topdir = a[4];
  lines[topdir][++cnt[topdir]] = $0;
}
END {
  for (d in lines) {
    print "=== " d " ===";
    for (i=1; i<=cnt[d]; i++) print lines[d][i];
    print "";
  }
}' | sort | head -500
